<template><form @submit.prevent='save' class='frm'><label>代码</label><input v-model='symbol' @input='search'><ul v-if='results.length' class='dropdown'><li v-for='r in results' @click='choose(r)'>{{r.symbol}} — {{r.description}}</li></ul><label>数量</label><input v-model.number='qty' type='number'><label>价格</label><input v-model.number='price' type='number'><button type='submit'>提交</button></form></template>
<script setup>import {ref} from 'vue';const symbol=ref('');const results=ref([]);const qty=ref(0);const price=ref(0);function search(){if(symbol.value.length<1){results.value=[];return;}fetch(`https://finnhub.io/api/v1/search?q=${symbol.value}&token=d19cvm9r01qmm7tudrk0d19cvm9r01qmm7tudrkg`).then(r=>r.json()).then(d=>{results.value=d.result.filter(x=>x.type==='Equity')})}function choose(r){symbol.value=r.symbol;results.value=[];}function save(){alert('保存:'+symbol.value);}</script>
<style scoped>.frm{display:flex;flex-direction:column;gap:8px}.dropdown{position:absolute;left:0;right:0;background:#000;border:1px solid #0f0;max-height:200px;overflow:auto;z-index:3000}.dropdown li{padding:4px;cursor:pointer}.dropdown li:hover{background:#0f0;color:#000}</style>